import{_ as t,o as a,c as s,ag as o}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"AI Chat","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-chat.md","filePath":"guide/ai-chat.md","lastUpdated":1773993597000}'),r={name:"guide/ai-chat.md"};function n(i,e,l,h,d,c){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="ai-chat" tabindex="-1">AI Chat <a class="header-anchor" href="#ai-chat" aria-label="Permalink to &quot;AI Chat&quot;">​</a></h1><p>The AI Chat panel lets you have a conversation about your lab results with an AI that already knows everything about your data — your biomarker history, lifestyle context, supplements, notes, and health goals.</p><h2 id="opening-the-chat" tabindex="-1">Opening the Chat <a class="header-anchor" href="#opening-the-chat" aria-label="Permalink to &quot;Opening the Chat&quot;">​</a></h2><p>Click the <strong>chat bubble</strong> in the bottom-right corner of the screen to slide the chat panel open. You can also click the <strong>Ask AI</strong> button in the header. Press <strong>Escape</strong> to close it.</p><div class="tip custom-block"><p class="custom-block-title">Chat FAB</p><p>The floating chat bubble (FAB) is always visible in the bottom-right corner, giving you one-tap access to the AI from any screen.</p></div><h2 id="setup-guide" tabindex="-1">Setup Guide <a class="header-anchor" href="#setup-guide" aria-label="Permalink to &quot;Setup Guide&quot;">​</a></h2><p>If no AI provider is configured, the chat panel shows a setup guide instead of the conversation view. The guide explains your provider options and includes a <strong>Connect with OpenRouter</strong> button for one-click OAuth setup — no API key needed. Once connected, the chat is ready immediately.</p><h2 id="what-the-ai-knows" tabindex="-1">What the AI Knows <a class="header-anchor" href="#what-the-ai-knows" aria-label="Permalink to &quot;What the AI Knows&quot;">​</a></h2><p>Every message you send includes a full snapshot of your data:</p><ul><li>All lab values across every draw date, with reference ranges and trend direction</li><li>Your nine <a href="/docs/guide/context-cards.html">Context Cards</a> (diet, sleep, exercise, environment, etc.)</li><li>Your <a href="/docs/guide/interpretive-lens.html">Interpretive Lens</a> and <a href="/docs/guide/health-goals.html">Health Goals</a></li><li>Your supplements and their date ranges</li><li>A timestamped change timeline for context cards (diet changes, stress level shifts, etc.) so the AI can correlate lifestyle changes with lab trends</li><li>Your notes</li><li>For female profiles: menstrual cycle data and phase context</li></ul><p>You do not need to paste your results into the chat. Just ask your question.</p><h2 id="active-model-display" tabindex="-1">Active Model Display <a class="header-anchor" href="#active-model-display" aria-label="Permalink to &quot;Active Model Display&quot;">​</a></h2><p>The chat header shows the name of your currently active AI model, so you always know which model is responding. Each message also includes a cost footnote showing the estimated token cost for that exchange.</p><h2 id="personalities" tabindex="-1">Personalities <a class="header-anchor" href="#personalities" aria-label="Permalink to &quot;Personalities&quot;">​</a></h2><p>The AI adopts a personality that shapes its communication style. Choose from three:</p><h3 id="default" tabindex="-1">Default <a class="header-anchor" href="#default" aria-label="Permalink to &quot;Default&quot;">​</a></h3><p>A clear, evidence-informed tone. Explains markers plainly, notes trends, and flags concerns without drama.</p><h3 id="house" tabindex="-1">House <a class="header-anchor" href="#house" aria-label="Permalink to &quot;House&quot;">​</a></h3><p>Takes on the style of a sharp, skeptical clinician who asks uncomfortable questions. Pushes back on assumptions and digs for root causes.</p><h3 id="custom" tabindex="-1">Custom <a class="header-anchor" href="#custom" aria-label="Permalink to &quot;Custom&quot;">​</a></h3><p>Create your own persona. Type a name in the custom personality field and click <strong>Generate</strong> — the AI will create a full personality profile for that persona, including communication style, analytical approach, and philosophical lens. You can edit the generated text before saving.</p><p>The <strong>Enforce evidence-based accuracy</strong> option (off by default) adds a strict disclaimer to the AI&#39;s instructions, keeping responses grounded in published research rather than speculation.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Custom personalities are saved per profile and persist across sessions. You can create a persona based on a specific medical philosophy, a fictional doctor character, or any style that makes conversations more useful for you.</p></div><h2 id="conversation-threads" tabindex="-1">Conversation Threads <a class="header-anchor" href="#conversation-threads" aria-label="Permalink to &quot;Conversation Threads&quot;">​</a></h2><p>The chat panel includes a <strong>thread rail</strong> on the left side — a list of your past conversations. Each thread is named automatically from your first message, and you can rename any thread by clicking its name.</p><ul><li>Start a new conversation at any time</li><li>Switch between threads without losing history</li><li>Up to 50 threads are stored per profile; the oldest are pruned automatically</li></ul><p>On mobile, tap the hamburger icon in the chat header to open the thread list, and use the back button to return to the conversation.</p><h2 id="image-attachments" tabindex="-1">Image Attachments <a class="header-anchor" href="#image-attachments" aria-label="Permalink to &quot;Image Attachments&quot;">​</a></h2><p>You can attach images to chat messages — photos of lab reports, supplement labels, food logs, skin conditions, or anything else you want the AI to see.</p><p><strong>How to attach:</strong></p><ul><li>Click the <strong>paperclip</strong> button in the chat input area</li><li><strong>Paste</strong> an image from your clipboard (Ctrl+V / Cmd+V)</li><li><strong>Drag and drop</strong> an image file onto the chat input</li></ul><p>Up to 5 images per message. Supported formats: JPEG, PNG, GIF, WebP.</p><h3 id="hd-mode" tabindex="-1">HD Mode <a class="header-anchor" href="#hd-mode" aria-label="Permalink to &quot;HD Mode&quot;">​</a></h3><p>The <strong>HD</strong> button next to the paperclip toggles between standard (1024px) and high-resolution (2048px) image quality. HD mode preserves more detail but uses more tokens. Standard mode is usually sufficient for lab reports and supplement labels; use HD for fine print or detailed photos.</p><h3 id="quality-warnings" tabindex="-1">Quality Warnings <a class="header-anchor" href="#quality-warnings" aria-label="Permalink to &quot;Quality Warnings&quot;">​</a></h3><p>Before sending, getbased analyzes each image and warns you if it detects issues:</p><ul><li><strong>Blurry</strong> — try holding steady or tapping to focus</li><li><strong>Too dark</strong> — try better lighting</li><li><strong>Overexposed</strong> — try less direct light</li><li><strong>Low resolution</strong> — the AI may struggle with fine details</li></ul><p>These checks save tokens by catching bad photos before they&#39;re sent.</p><h3 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h3><p>All image metadata is automatically stripped before sending. EXIF data — GPS location, camera model, timestamps, device serial numbers — is removed during the resize step. Only raw pixel data reaches your AI provider.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The attach and HD buttons only appear when your active model supports vision (image input). If you don&#39;t see them, switch to a vision-capable model in Settings.</p></div><h2 id="web-search" tabindex="-1">Web Search <a class="header-anchor" href="#web-search" aria-label="Permalink to &quot;Web Search&quot;">​</a></h2><p>The <strong>Web</strong> toggle in the chat header lets the AI search the internet before responding. This is useful for questions about recent studies, drug interactions, supplement research, or anything where up-to-date information matters.</p><p>Toggle it on, ask your question, and the AI will pull in current web results alongside your lab context.</p><div class="warning custom-block"><p class="custom-block-title">Higher cost</p><p>Web search injects search results into the AI&#39;s context, significantly increasing input tokens. Expect messages to cost 2–4x more than normal. The cost footnote shows a 🌐 web indicator when search was active.</p></div><div class="tip custom-block"><p class="custom-block-title">Availability</p><p>Web search is available with <strong>OpenRouter</strong> and <strong>Venice</strong> only. The toggle is hidden when using Anthropic or Local AI.</p></div><h2 id="per-marker-ai-explanations" tabindex="-1">Per-Marker AI Explanations <a class="header-anchor" href="#per-marker-ai-explanations" aria-label="Permalink to &quot;Per-Marker AI Explanations&quot;">​</a></h2><p>From any marker&#39;s detail view (click a marker name in the sidebar or on the dashboard), you will find an <strong>Ask AI</strong> button. This opens a pre-populated chat asking the AI to explain that specific marker in the context of your results — without you having to type anything.</p><h2 id="markdown-responses" tabindex="-1">Markdown Responses <a class="header-anchor" href="#markdown-responses" aria-label="Permalink to &quot;Markdown Responses&quot;">​</a></h2><p>The AI&#39;s responses are rendered with full markdown formatting:</p><ul><li>Headings, bold, and italic text</li><li>Bullet and numbered lists</li><li>Code blocks and inline code</li><li>Clickable links</li></ul><p>Responses stream in smoothly as the AI generates them, with a typewriter effect that trickles text at a steady rate for a pleasant reading experience.</p><h2 id="token-costs-and-what-to-expect" tabindex="-1">Token Costs and What to Expect <a class="header-anchor" href="#token-costs-and-what-to-expect" aria-label="Permalink to &quot;Token Costs and What to Expect&quot;">​</a></h2><p>Every chat message sends your full lab context + conversation history to the AI. Here&#39;s what makes up the token count:</p><table tabindex="0"><thead><tr><th>Component</th><th>Typical size</th><th>Notes</th></tr></thead><tbody><tr><td>System prompt</td><td>~1,300 tokens</td><td>Fixed — personality instructions, rules</td></tr><tr><td>Lab context</td><td>2,000–15,000 tokens</td><td>Scales with number of draw dates, markers, and filled context cards</td></tr><tr><td>Conversation history</td><td>0–10,000+ tokens</td><td>Last 30 messages (both yours and AI responses)</td></tr><tr><td>Image (current message only)</td><td>1,000–5,000 tokens per image</td><td>Only attached to the message being sent, not stored in history</td></tr><tr><td><strong>Total input per message</strong></td><td><strong>~3,000–25,000+ tokens</strong></td><td></td></tr></tbody></table><h3 id="what-drives-the-cost-up" tabindex="-1">What drives the cost up <a class="header-anchor" href="#what-drives-the-cost-up" aria-label="Permalink to &quot;What drives the cost up&quot;">​</a></h3><ul><li><strong>More draw dates</strong> — each date adds values to every marker. 2 dates ≈ 3k lab context; 8+ dates ≈ 10k+</li><li><strong>Filled context cards</strong> — each of the 9 lifestyle cards adds 50–300 tokens when filled</li><li><strong>Long conversations</strong> — AI responses are often 300–800 tokens each. After 10 back-and-forth exchanges, history alone can be 5k–8k tokens</li><li><strong>Images</strong> — a single standard-quality image adds ~1,500–3,000 input tokens. HD images cost more. Images are only sent with the current message, never re-sent in history</li><li><strong>Web search</strong> — when the Web toggle is on, search results are injected into the context, adding thousands of tokens. Expect 2–4x the normal cost per message</li></ul><h3 id="realistic-cost-examples" tabindex="-1">Realistic cost examples <a class="header-anchor" href="#realistic-cost-examples" aria-label="Permalink to &quot;Realistic cost examples&quot;">​</a></h3><p>Using Claude Sonnet 4 via OpenRouter (~$3/$15 per 1M input/output tokens):</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Input tokens</th><th>Output tokens</th><th>Cost per message</th></tr></thead><tbody><tr><td>First message, 2 draw dates, no images</td><td>~4,000</td><td>~500</td><td>~$0.02</td></tr><tr><td>Mid-conversation (10 messages), 4 draw dates, all cards filled</td><td>~15,000</td><td>~600</td><td>~$0.05</td></tr><tr><td>Long conversation (20+ messages), 8 draw dates, 1 image</td><td>~25,000</td><td>~800</td><td>~$0.09</td></tr><tr><td>Discuss mode (2 personas, 3 rounds each)</td><td>~20,000 × 6</td><td>~600 × 6</td><td>~$0.40 total</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Cost-saving tips</p><ul><li><strong>Start new threads</strong> — click &quot;New Chat&quot; to reset conversation history to zero. This is the single biggest cost saver</li><li><strong>Use standard image mode</strong> (not HD) unless you need fine detail</li><li><strong>Local AI is free</strong> — run Ollama or LM Studio locally for unlimited chat at zero cost</li><li><strong>Venice</strong> offers free-tier models with no per-token charges</li></ul></div><h3 id="each-message-shows-its-cost" tabindex="-1">Each message shows its cost <a class="header-anchor" href="#each-message-shows-its-cost" aria-label="Permalink to &quot;Each message shows its cost&quot;">​</a></h3><p>Every AI response includes a footnote showing the model name, estimated cost, and total token count — so you always know exactly what you&#39;re spending.</p><h2 id="choosing-a-provider" tabindex="-1">Choosing a Provider <a class="header-anchor" href="#choosing-a-provider" aria-label="Permalink to &quot;Choosing a Provider&quot;">​</a></h2><p>The AI chat works with any of the four supported providers: Anthropic, OpenRouter, Venice, or Local AI. See <a href="/docs/guide/ai-providers.html">AI Providers</a> to configure your key or local server. The chat is not available until a provider is set up.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Conversations are stored locally in your browser and encrypted if you have set a passphrase. The last 30 messages from each conversation are sent to the AI provider with every request to maintain context. Your provider&#39;s privacy policy applies to that data.</p></div>',66)])])}const g=t(r,[["render",n]]);export{u as __pageData,g as default};
